function fib(int n)
if(n == 0 || n == 1)
return 1;
else
return fib(n-1) + fib(n-2);
function fib(int n)
int first = 0;
int second = 1;
int tmp;
for(i = 1 to n)
tmp = first + second;
first = second;
second = tmp;
end for
return first;

